void test_CB_26_0000()
{
    if (skip_test_CB_26_0000)
    {
        TEST_SKIP("Skipping");
        return;
    }
    mmap.Reset();

    // Initial state

    WriteRegisterWord(RegisterType::PC, 0x50B7);
    WriteRegisterWord(RegisterType::SP, 0xFBA1);
    WriteRegisterByte(RegisterType::A, 0xD4);
    WriteRegisterByte(RegisterType::B, 0xC1);
    WriteRegisterByte(RegisterType::C, 0xA6);
    WriteRegisterByte(RegisterType::D, 0xD0);
    WriteRegisterByte(RegisterType::E, 0x90);
    WriteRegisterFlag(0xD0);
    WriteRegisterByte(RegisterType::H, 0xDB);
    WriteRegisterByte(RegisterType::L, 0x3D);
    mmap.DisableIME();
    WriteRegisterByte(RegisterType::IE, 0x00);
    WriteMemory(0xDB3D, 0x03);
    WriteMemory(0x50B8, 0x26);
    WriteMemory(0x50B7, 0xCB);

    // Execute step
    {
        auto resultByte = mmap.ReadByte(mmap.ReadPC());
        TEST_ASSERT_(resultByte.IsSuccess(), "%s", resultByte.GetStatusDescription());
        auto ticks = ExecuteActiveDecoder(static_cast<const Byte&>(resultByte), mmap);
        TEST_ASSERT(ticks == GetInstructionTicks(static_cast<const Byte&>(resultByte), 0x00));

        // Execute additional step for prefix
        auto resultByte2 = mmap.ReadByte(mmap.ReadPC());
        TEST_ASSERT_(resultByte2.IsSuccess(), "%s", resultByte2.GetStatusDescription());
        auto ticks2 = ExecuteActiveDecoder(static_cast<const Byte&>(resultByte2), mmap);
        TEST_ASSERT(ticks2 == GetInstructionTicks(static_cast<const Byte&>(resultByte2), 0xCB));
        TEST_ASSERT(ticks + ticks2 == 16);
    }

    // Final state
            
    CheckRegisterByte(RegisterType::A, 0xD4);
    CheckRegisterByte(RegisterType::B, 0xC1);
    CheckRegisterByte(RegisterType::C, 0xA6);
    CheckRegisterByte(RegisterType::D, 0xD0);
    CheckRegisterByte(RegisterType::E, 0x90);
    CheckRegisterFlag(0x00);
    CheckRegisterByte(RegisterType::H, 0xDB);
    CheckRegisterByte(RegisterType::L, 0x3D);
    CheckRegisterWord(RegisterType::PC, 0x50B9);
    CheckRegisterWord(RegisterType::SP, 0xFBA1);
    TEST_ASSERT(!mmap.IMEEnabled());
    CheckMemory(0x50B7, 0xCB);
    CheckMemory(0x50B8, 0x26);
    CheckMemory(0xDB3D, 0x06);
}

